var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"크흠.","JPN":"コホン。","ENG":"Ahem.","TWN":"咳咳。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"감히 이 어둠의 신부를 빼놓고 피로연을 열다니!","JPN":"この闇の花嫁を、差し置いて、披露宴を、するとは！","ENG":"How dare you start the reception without me, the bride of darkness!","TWN":"我就是壞新娘，辦喜宴竟然沒邀請我！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"저쪽에서, 날 빤히 쳐다보고 있는, 저기 저 신부를, 가만 두지 않을 테다!","JPN":"向こうから、私を見ている、あの花嫁を、ただではおかないぞ！","ENG":"I won't let, that bride that's looking at me, have a happy wedding!","TWN":"那邊那個，眼巴巴瞪著我的新娘，我是不會放過她的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"잉그리드… 너무 책 읽는 말투야…….","JPN":"イングリッド……棒読み過ぎだよ……","ENG":"Ingrid... Your acting is so stiff...","TWN":"英格麗…怎麼好像在背稿……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후후, 그래도 생각보다는 훌륭한데?","JPN":"ふふっ。でも思っていたよりいいわよ？","ENG":"Ha ha, it's better than I thought, though.","TWN":"呵呵，不過好像比我想像中來得好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"고양이처럼 마구마구 할퀴어 주마!","JPN":"猫のように引っ搔いてやる！","ENG":"I'll scratch you up, like a feisty cat!","TWN":"我會像貓一樣瘋狂抓你！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"미, 미쳤어?! 진짜로 덤비면 어떡해!","JPN":"バ、バカ！？　本当に飛び掛かってきてどうするんだ！","ENG":"A-are you insane?! You can't actually jump on me like that!","TWN":"你，你瘋啦？！竟然真的撲上來！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L14_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"하, 하지만 에블린이 진짜처럼 하랬어!","JPN":"で、でも、エヴリンが本物に見えるようにやれって！","ENG":"B-but, Evelyn wanted it to look real!","TWN":"可，可是，是伊芙琳叫我來真的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"적당히 해야지! 적당히!","JPN":"ほどほどにしろ！　ほどほどに！","ENG":"To \\"look\\" real! \\"Look!\\"","TWN":"不用啦！點到為止就好！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"방금 휘두른 거, 가짜 낫이겠지?","JPN":"今振り回した鎌、本物じゃないよな？","ENG":"That thing just now, it must be a fake scythe, right?","TWN":"剛才她揮的那把鐮刀是假的吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"테이블 모서리가 잘려 나갔는데……?","JPN":"テーブルの角が切り取られてるけど……？","ENG":"I think the corner of that table's been sliced off...","TWN":"桌角都被切掉咧……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"어머나. 소품이나 연출에도 꽤 공들였네요.","JPN":"おお。小物や演出にも手が込んでいますね。","ENG":"Oh my. They've certainly put a lot of effort into the props and special effects.","TWN":"哇，在道具和演技上都有下功夫呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"카페 이벤트치고 퀄리티가 상당한데요?","JPN":"カフェのイベントにしてはなかなかのクオリティーです！","ENG":"It's very high quality for a cafe event.","TWN":"以咖啡廳的活動來說，品質算很高呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"공주님이 위험해요! 마녀 언니!","JPN":"お姫様が危ないよ！　魔女のお姉ちゃん！","ENG":"The princess is in danger! Ms. Witch!","TWN":"魔女姊姊！公主有危險！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그러게. 저대로 두면 사악한 어둠의 신부에게 잡아 먹힐 수도 있겠어.","JPN":"そうね。このままじゃ邪悪な闇の花嫁に捕まって食べられてしまうかもしれないわ。","ENG":"Yes. She'll be eaten by the bride of darkness unless we do something.","TWN":"是呀，不快點幫幫公主的話，公主會被壞新娘吃掉的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"히, 히익!","JPN":"ひ、ひいっ！","ENG":"E-eeek!","TWN":"什麼！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"도와 줄게요! 어떻게 하면 돼요?","JPN":"助けてあげる！　どうすればいいの？","ENG":"I'll help! What should I do?!","TWN":"我要幫公主！我要做什麼呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"잘 들어. 신부를 도와주려면…….","JPN":"よく聞いて。お姫様を助けるには……","ENG":"Listen carefully. If you want to help the princess…","TWN":"你要聽好喔，想幫助新娘的話……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"웨딩 디저트를 먹어서 이 유리병에 <color=#ffd34c>하트 포인트</color>를 쌓아야 된단다.","JPN":"ウェディングデザートを食べて、このガラスの瓶に<color=#ffd34c>ハートポイント</color>を集めるの。","ENG":"You have to eat the wedding desserts and gather <color=#ffd34c>Heart Points</color> in this glass jar.","TWN":"就必須吃掉婚禮甜點，將<color=#ffd34c>愛心點數</color>累積到玻璃瓶裡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 공주가 악당을 물리칠 수 있는 힘을 얻거든.","JPN":"そうすればお姫様が悪党を蹴散らすことのできる力を得られるわ。","ENG":"That's how the princess gets the power to defeat the villain.","TWN":"這樣公主就可以獲得打敗壞人的力量！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"엄마! 아빠! 나 웨딩 디저트 사줘!!","JPN":"ママ！　パパ！　ウェディングデザート買って！！","ENG":"Mom! Dad! I want wedding desserts!!","TWN":"媽媽！爸爸！人家要買婚禮甜點！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이게 바로 어른의 마케팅……?","JPN":"これがすなわち、大人のマーケティング……？","ENG":"Is this how grown-ups make money...?","TWN":"這就是大人的行銷手法嗎……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗♪","JPN":"ふふっ♪","ENG":"Ha ha ♪","TWN":"呵呵♪"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"으음, 그런 컨셉이구나.","JPN":"う～ん、そういうコンセプトなんだな。","ENG":"Mmm, I get the theme now.","TWN":"喔喔，原來是這種路線。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"흐아암. 뭔가 화려하긴 한데, 차원 함선도 없고…….","JPN":"ふわあ。華やかではあるけれど、次元艦船もないし……","ENG":"*Yawn* It's extravagant, but there aren't any dimensional ships...","TWN":"嗯嗯，場面是很浩大啦，但是又沒有次元艦船……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"생각보다는 반응이 별론데……?","JPN":"思っていたより反応が悪い……？","ENG":"The reactions aren't as positive as we hoped for.","TWN":"反應好像不太好……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이걸로는 부족한가 봐. 뭐라도 해야 할 것 같아!","JPN":"これだけじゃ足りないのね。何か他にしないと！","ENG":"I guess this isn't enough. We should do something!","TWN":"這樣好像還不夠，是不是要再來點其他噱頭！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"낫을 더 휘두를까?","JPN":"鎌をもっと振り回そうか？","ENG":"Should I swing the scythe more?","TWN":"要我再揮一次鐮刀嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"그건 절대 안 돼!","JPN":"それは絶対にダメだ！","ENG":"NO!","TWN":"絕對不行！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"눈 먼 공격에 다친 손님이라도 생기면 네 월급에서 깔 줄 알아!","JPN":"むやみに攻撃してお客さんが怪我でもしたら、汝の給料から差し引くぞ！","ENG":"It'll come out of your paycheck if a customer gets injured.","TWN":"要是你傷到客人，看我怎麼扣你的薪水！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"치사하게 월급 가지고 그러기냐!","JPN":"給料を盾に取るなんてずるい！","ENG":"Gosh, my paycheck?! Really?!","TWN":"真卑鄙，竟然拿薪水來威脅我！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 그럼 어떡해! 손님들이 떠나버리기라도 하면…….","JPN":"そ、それじゃあどうするの？　お客さんが帰っちゃったら……","ENG":"W-what should we do, then?! What if the customers leave...","TWN":"那，那怎麼辦！客人都走掉的話……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"좋은 방법이 있어.","JPN":"いい方法があるよ。","ENG":"I have a good idea.","TWN":"我有辦法。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"그러니까, 낫을 휘두르는 건 좋은 방법이 아니래도?","JPN":"鎌を振り回すのはいい方法ではないと言ったはずだが？","ENG":"I told you, swinging your scythe is not a good idea.","TWN":"我說過了，揮鐮刀不算是好辦法。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"그런 거 아니야!","JPN":"そういうのじゃなくて！","ENG":"It's not that!","TWN":"不是那個啦！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"네크로노미코에서도 전개가 조금 늘어진다 싶을 때마다 이런 방법을 썼었어!","JPN":"ネクロノミコでも展開がちょっと間延びしてくるたびにこの方法を使ってたんだ！","ENG":"This is what they did when it was feeling a little stale in Necronomiko!","TWN":"亡靈之書中，每次覺得劇情發展有點慢的時候，也都會用這個辦法！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 설마 그 방법?!","JPN":"あっ、まさかあの方法！？","ENG":"Oh! Are you talking about...!","TWN":"喔！難道是那個辦法？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"맞아. 바로 새로운 악당을 등장시키는 거야!","JPN":"そう。つまり新しい悪党を登場させる！","ENG":"Yes. Send out a new villain!","TWN":"沒錯，就是讓新的反派登場！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"매번 보는 악당에 질려 떠나려던 시청자들을 다시 돌아오게 만든 비장의 한 수지.","JPN":"毎回登場する悪党に飽きて離れようとしていた視聴者を、もう一度戻ってこさせる奥の手なの。","ENG":"It's the ultimate way to make the audience, who are bored of the old villain, come back to the show.","TWN":"這是讓那些看膩同一個反派想棄劇的觀眾重新回鍋的秘招！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그거 괜찮은 생각인데?","JPN":"いいんじゃない？","ENG":"That's not a bad idea.","TWN":"這個辦法好像不錯喔？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"하지만 여기서 갑자기 새로운 악당을 구하려고 해도…….","JPN":"でもここで突然新しい悪党役を見つけようとしても……","ENG":"But, how are we going to find a new villain here...?","TWN":"不過現在突然要上哪去找新的反派……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"훗.","JPN":"ふっ。","ENG":"Heh.","TWN":"呵。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"이럴 때 쓰라고 마법이 있는 거지.","JPN":"こういう時のために魔法があるんだ。","ENG":"That's what magic is for.","TWN":"魔法就是在這種時候派上用場的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"웨딩 드레스 다시 가져와 봐.","JPN":"ウェディングドレス、もう一度持ってこい。","ENG":"Bring the wedding dress out again.","TWN":"把婚紗拿來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"응!","JPN":"うん！","ENG":"Okay!","TWN":"好！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"괜찮겠어? 오늘 마법을 너무 많이 사용하는데.","JPN":"大丈夫なの？　今日は魔法をずいぶん使っているけれど。","ENG":"Are you sure? You've been using a lot of magic today.","TWN":"沒問題吧？今天使用魔法的頻率好像有點高。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"베아트릭스 가문을 뭘로 보는 거야? 하루종일 마법을 써도 하품 한 번 할까 말까한데.","JPN":"ベアトリクス家をなめるなよ。一日中魔法を使ったとしても、あくびが出るくらいだ。","ENG":"I'm a Beatrix. We barely yawn after using magic all day.","TWN":"你是不是太小看貝阿朵莉絲家族啦？就算一整天都用魔法，我大氣都不會喘一下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으음, 네가 그렇다면야…….","JPN":"うーん、それならいいけど……","ENG":"Mmm, well, if you say so...","TWN":"好吧，既然你那麼說……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"가져왔어!","JPN":"持ってきたよ！","ENG":"Here they are!","TWN":"拿來囉！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"자. 그럼 다들 2막 준비해 두라고.","JPN":"さあ、ではみんな第2幕の準備をしておけ。","ENG":"Now. Everyone, get ready for the second act.","TWN":"好，那大家準備第二幕吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_QM","text":{"KOREA":"달콤한 냄새와 들뜬 인간들이라…….","JPN":"甘い香りと浮足立った人間たち……","ENG":"A sweet scent and excited humans...","TWN":"甜甜的味道和興奮的人類……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_QM","text":{"KOREA":"여기에 비명을 끼얹는다면, 보다 완벽한 피로연이 될 것 같군요.","JPN":"ここに悲鳴が加われば、完璧な披露宴になりますね。","ENG":"With the addition of screaming, it would make the perfect wedding reception.","TWN":"如果再加上慘叫聲，喜宴似乎會更加完美呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"하… 하랍?!","JPN":"ハ……ハーラヴ！？","ENG":"H-Harab?!","TWN":"哈……哈拉普？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아앗! 저 드레스 내가 만든 건데?!","JPN":"ああっ！　あのドレス私が作ったやつ！？","ENG":"Wha-?! That's the dress I made!","TWN":"喔喔！那是我做的婚紗？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"후후후. 소란스럽네요.","JPN":"ふふふ。騒々しいですね。","ENG":"Hah hah hah. What a ruckus.","TWN":"呵呵呵，好吵。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"우리, 조금 더 솔직해지는 건 어떨까요?","JPN":"もう少し素直になりませんか？","ENG":"Why don't we be a little more honest with each other?","TWN":"我們彼此之間，再更坦承一點吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"사실은… 저를 많이 보고 싶어했다고 말이죠.","JPN":"実は……私に会いたくって仕方がなかったんでしょう。","ENG":"You can just tell me... that you've missed me.","TWN":"其實……你很想我吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"저게 무슨 정신 나간 소리…….","JPN":"な、なにバカなことを……","ENG":"What in the world is she saying that for...?","TWN":"她在胡說八道什麼……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"제 주인께선 어디로 가셨을까요?","JPN":"私のご主人様はどちらに行かれたのかしら？","ENG":"Where could my master be?","TWN":"我的主人呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"하루라도 빨리 여. 보. 라고 불러 드리고 싶은데.","JPN":"一日も早く、あ・な・たとお呼びしたいのに。","ENG":"I can't wait a day longer to call him \\"Sweet Heart.\\"","TWN":"我好想早點叫你一聲老，公。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"잠시만.","JPN":"待って。","ENG":"Wait.","TWN":"怎麼回事？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"저 녀석한테서 왜 네 힘이 느껴지는 거지?","JPN":"あいつからどうしてあなたの力を感じるの？","ENG":"Why do I feel your power from her?","TWN":"我怎麼從那傢伙身上感覺到你的力量？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"그야 내가 마법을 건 드레스에 나타났으니…… 까?","JPN":"そりゃ、妾の魔法がかかったドレスを着ている……から？","ENG":"Because... She's in the dress that I used magic on...?","TWN":"因為我剛才對那件婚紗……施魔法？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"아! 설마?","JPN":"あ、まさか！","ENG":"Oh! Wait!","TWN":"難道是？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"마법 자체에는 문제가 없었을 거고… 웨딩 디저트에 건 마법들하고 연쇄 반응을 일으킨 걸 수도 있어.","JPN":"魔法自体に問題はないけれど……ウェディングデザートにかけた魔法と連鎖反応を起こしているのかもしれないわね。","ENG":"There shouldn't have been a problem with the magic itself... So it might've triggered a chain reaction with the spell I cast on wedding desserts...","TWN":"魔法本身應該沒問題……但婚禮甜點也有魔法，或許因此產生連鎖反應。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으음, 하지만 저런 이상한 반응이 나올 만한 주문은 없었을 텐데…….","JPN":"うーん、でもあんなおかしな反応が出るような呪文はなかったはずだけど……","ENG":"Mmm, but I'm pretty sure there was no spell that would've caused something as odd as that...","TWN":"呃，可是應該沒有會出現那種奇怪反應的咒語吧……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"……연인끼리 솔직해지는 마법을 걸어 놓긴 했어.","JPN":"……恋人同士、素直になる魔法をかけはした。","ENG":"...I've cast a spell where lovers become honest with each other.","TWN":"……我剛施的魔法是讓情侶之間變得更坦誠的魔法。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"설마 그것 때문은 아니겠지만.","JPN":"まさかそのせいじゃないとは思うが。","ENG":"But that shouldn't be it.","TWN":"應該不會是因為這個吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으음……?","JPN":"うーん……？","ENG":"Hmm…?","TWN":"呃……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아무래도 원인을 찾은 것 같은데?","JPN":"原因はそれなんじゃない？","ENG":"I think we figured out what the cause is.","TWN":"這應該就是原因。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"하, 하지만 결혼을 앞두고 꼭 필요한 일이잖아! 서로에게 솔직해지는 거!","JPN":"で、でも結婚を控えて必ず必要なことじゃないか！　お互いに素直になることは！","ENG":"B-but, it's necessary, right?! Before getting married! Being honest with each other!","TWN":"可，可是，這不是婚前應該要做的嗎！就是對彼此坦誠！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"때로는 서로에게 조금 덜 솔직한 게 관계에 더 좋기도 한 법이지.","JPN":"時にはお互いばか正直でないことが関係の維持に良いこともあるのよ。","ENG":"Sometimes, being a little less honest helps strengthen the relationship.","TWN":"有時候別那麼坦誠反而對關係有益呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"오늘 대규모 마법을 일으킨 데다가 네 생각까지 얽혀 들어가서 하랍의 외형이 된 건가 봐.","JPN":"今日の大規模な魔法を使ったのに加えて、あなたの考えまで魔法に入ってしまって、ハーラヴの外見になったようね。","ENG":"You did cast a lot of spells today, and your unconscious thoughts must have been mixed into this one. As a result, it ended up looking like Harab.","TWN":"可能是因為今天施太多魔法，加上還有摻雜你自己的想法，所以才變成哈拉普的外貌。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 그럼 저 사람은 하랍이 아니라는 얘기인가요?","JPN":"じゃ、じゃあ、あの人はハーラヴじゃないってことですか？","ENG":"Y-you mean, that's not the real Harab?","TWN":"這麼說，那個人不是哈拉普？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그렇지. 외형만 같은 이형의 존재야.","JPN":"そう。見た目が同じでも異なる存在よ。","ENG":"Correct. It's just a magical entity with the same appearance.","TWN":"沒錯，她只是長得像哈拉普的仿冒品。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"저걸 그럼 어떻게 처리한담……?","JPN":"あれをどうしたらいいのかしら……","ENG":"Now, how should we take care of that...?","TWN":"該拿她怎麼辦呢……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"새로운 신부가 나타난 건가?","JPN":"新しい花嫁が現れたのか？","ENG":"Is that a new bride?","TWN":"是新的新娘出場嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이번 신부는 채찍도 들고 있어! 그런 컨셉도 괜찮나?!","JPN":"今回の花嫁は鞭も持っているわ！　そんなコンセプトもありなの！？","ENG":"This one has a whip! Is that okay?!","TWN":"這次的新娘還拿著鞭子欸！可以玩這麼大嗎？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"신부가… 둘이로군요.","JPN":"花嫁が……二人ですね。","ENG":"There are... two, brides.","TWN":"原來……有二位新娘嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"으음, 바람을 핀 모양이죠? 따끔한 체벌을 받기 위해 벌인 일일 거라고는 해도, 괘씸하네요.","JPN":"浮気をしていたのでしょうか？　厳しい罰が欲しいがためにやったことだとしても腹立たしいですね。","ENG":"Hmm, an affair, I assume. Even if it was in order to receive harsh punishment, how naughty.","TWN":"意思是，新郎劈腿嗎？真是可惡，就算是想要得到嚴厲的懲罰也不能這樣吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"이곳에 신부가 둘일 필요는 없습니다.","JPN":"ここに花嫁は二人も必要ありません。","ENG":"There is no need for two brides here.","TWN":"這裡不需要二位新娘。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"그이와 저는 서로 솔직한 취향을 공유한 상황……. 당신은 저희 예식의 화동이나 하시죠.","JPN":"彼と私はお互いの好みを正直に打ち明けた間柄……あなたは結婚式の花撒きでもしてください。","ENG":"He and I have already been honest with each other's tastes... It would better fit you to be the flower girl of our wedding ceremony.","TWN":"我和他興趣相投……你就在我們的婚禮上當花童吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"만들어진 지 1분도 안 된 애송이가 감히 누구 앞에서 까불어?","JPN":"作られて1分も経たない若造が、調子に乗るなよ？","ENG":"Who do you think you're talking to, you one-minute-old infant?","TWN":"你才出場一分鐘而已，竟然敢在我面前放肆？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"얌전히 드레스만 내놓고 사라지시지?","JPN":"大人しくドレスをおいて消えるんだな。","ENG":"Give us the dress back and get lost.","TWN":"乖乖把婚紗給我交出來，然後滾蛋！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"그런 자비 없는 명령이라니. 생긴 것과는 다르시군요.","JPN":"そんな慈悲のない命令をするなんて。見た目とは違うんですね。","ENG":"I would've never known you'd be so ruthless with those looks.","TWN":"長得可可愛愛的，手段卻如此粗暴，真是人不可貌相呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"하지만 전 명령을 내리는 쪽이지, 받는 쪽은 아니랍니다.","JPN":"ですが、私は命令をする側であり、される側ではありません。","ENG":"However, I'm the one who gives orders, not the other way around.","TWN":"不過我是屬於發號施令的人，而不是服從命令的人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"뭐, 뭐라는 거야, 진짜!","JPN":"な、なんだというんだ、まったく！","ENG":"W-what is she talking about?!","TWN":"你，你說什麼，可惡！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L14_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"곧 피로연이 시작될 텐데, 우리 여보가 돌아오기 전까지 당신을 해결하겠습니다.","JPN":"まもなく披露宴が始まりますから、私の夫が到着するまでにあなたを片づけます。","ENG":"The wedding reception is beginning soon, and you shall be dealt with before my sweetheart returns.","TWN":"婚宴馬上就要開始了，我會在老公回來前把你解決掉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"식의 주인은 나와 그이, 오로지 둘뿐. 필요하다면…… 당신과 싸워 그이를 쟁취하죠.","JPN":"式の主人公になれるのは私と彼、たった二人です。必要なら……あなたと戦って彼を奪い取りましょう。","ENG":"He and I are the only stars of the ceremony. If necessary... I shall fight you to win him over.","TWN":"婚禮的主角就只能是我和他二個人而已，若是有必要……我會從你手上把他搶過來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"그놈의 그이가 대체 누군데!","JPN":"彼っていうのはいったい誰だというんだ！","ENG":"Who the heck is this \\"he\\" anyway?!","TWN":"你說的那個他到底是誰啦！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"우리 카페에 스크래치 하나라도 냈다간 얌전히 드레스로 돌아가게 해달라고 빌게 만들 줄 알아!","JPN":"うちのカフェに傷一つでも付けてみろ。ドレスに戻してくださいと哀願させてやる！","ENG":"You'll be begging to go back into the dress if you make a dent in my cafe!","TWN":"只要我們的咖啡廳出現一條刮痕，我就會讓你吃不完兜著走！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"의외로 저와 통하는 구석도 있으시군요.","JPN":"意外と私に通じるところもあるのですね。","ENG":"Oh, it seems like you and I are not that different.","TWN":"沒想到我們的想法一致呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_FAKE","text":{"KOREA":"그럼 어디 한번…… 애써 보시죠?","JPN":"では一度……やってみましょうか？","ENG":"In that case... try your best.","TWN":"那你就……放馬過來吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_FAKE","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};